using System;
using System.Drawing.Design;
using System.Windows.Forms;
using System.Windows.Forms.Design;

public class MyDropDownEditor : UITypeEditor
{
    public override object EditValue(ITypeDescriptorContext context,
        IServiceProvider provider, object value)
    {
        var editorService = provider?.GetService(typeof(IWindowsFormsEditorService))
            as IWindowsFormsEditorService;

        if (editorService is null)
            return value;

        // .NET 9 breaking change: DropDownControl now throws ArgumentNullException
        // if passed null. Guard against null controls.
        Control dropDown = CreateDropDown(value);
        if (dropDown is not null)
        {
            editorService.DropDownControl(dropDown);
            value = GetValueFromDropDown(dropDown);
        }

        return value;
    }

    private Control CreateDropDown(object currentValue)
    {
        var listBox = new ListBox();
        listBox.Items.AddRange(new object[] { "Option1", "Option2", "Option3" });
        listBox.SelectedItem = currentValue;
        return listBox;
    }

    private object GetValueFromDropDown(Control dropDown)
    {
        return (dropDown as ListBox)?.SelectedItem;
    }

    public override UITypeEditorEditStyle GetEditStyle(ITypeDescriptorContext context)
        => UITypeEditorEditStyle.DropDown;
}

